USE CATALOG `workspace`;
USE SCHEMA `salesdb`;

SHOW TABLES; 

DESCRIBE TABLE dim_customers;
DESCRIBE TABLE workspace.salesdb.dim_products; 

SELECT DISTINCT country FROM dim_customers; 

SELECT product_name, category, subcategory FROM dim_products;

--Total Sales
SELECT SUM(sales_amount) AS Total_Sales FROM fact_sales;

-- Total Customers
SELECT COUNT(DISTINCT customer_id) AS total_customers FROM dim_customers; 

--Total Orders
SELECT COUNT(DISTINCT order_number) AS total_orders FROM fact_sales; 

--Sales by Product
SELECT c.product_name, SUM(f.sales_amount) FROM dim_products c LEFT JOIN fact_sales f ON c.product_key = f.product_key GROUP BY c.product_name ORDER BY SUM(f.sales_amount) DESC; 

--Sales by Category
SELECT c.category, SUM(f.sales_amount) FROM
dim_products c LEFT JOIN fact_sales f ON c.product_key = f.product_key GROUP BY c.category ORDER BY SUM(f.sales_amount) DESC; 

-- Orders Over Time
SELECT date_trunc('month',order_date), SUM(sales_amount) FROM fact_sales GROUP BY date_trunc('month',order_date);

